INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('26-marketing-os',3,26,'MARKETING OS','He dieu hanh marketing',26,'draft','2026-06-20T15:57:00Z','2026-06-20T15:57:00Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fc96301e-74d2-4b4b-ac73-dc9099cc44ca','26-marketing-os',NULL,2,'24.1 Bảy mục tiêu cốt lõi của Marketing OS','241-bay-muc-tieu-cot-loi-cua-marketing-os',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2bd7203f-e50f-491d-b5bd-287e1f122d15','fc96301e-74d2-4b4b-ac73-dc9099cc44ca',0,'text','Nếu *Strategy OS* là bản thiết kế la bàn định hướng cho toàn bộ đế chế nha khoa, thì **Marketing OS** chính là động cơ phản lực, chịu trách nhiệm thu hút dòng traffic sạch và khơi thông dòng chảy dữ liệu khách hàng tiềm năng đổ về đầu phễu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('79022dac-f758-4aec-a455-20597ee1c54d','fc96301e-74d2-4b4b-ac73-dc9099cc44ca',1,'text','Trong hệ điều hành **Dental Empire OS**, chúng tôi tuyên chiến với tư duy tiếp thị chộp giật truyền thống nơi phòng khám cúng tiền cho Facebook/Google Ads để đổi lấy những tin nhắn rác hoặc những số điện thoại ảo ham rẻ. *Marketing OS* được kiến tạo để số hóa sự thấu cảm, lấy **Giáo dục y khoa thường thức làm gốc** để biến mạng lưới truyền thông thành một bộ lọc khách hàng tự động.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bcf2222a-79b3-4124-aa6c-c1be38f8bb32','fc96301e-74d2-4b4b-ac73-dc9099cc44ca',2,'text','Hệ điều hành tiếp thị hằng ngày phải kiểm soát và nghiệm thu thành công 7 mục tiêu chuyển đổi nhận thức sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('21b43a05-b28c-4ec0-a328-ee5818926621','fc96301e-74d2-4b4b-ac73-dc9099cc44ca',3,'text','- **Tạo nhận biết thương hiệu diện rộng (Brand Awareness):** Định vị thương hiệu nha khoa tử tế, chuyên nghiệp trong tâm trí thị trường mục tiêu tại khu vực địa lý phòng khám vận hành.- **Xây dựng niềm tin sắt đá (Trust Architecture):** Hóa giải nỗi sợ hãi sinh học (sợ đau, sợ biến chứng) và rào cản tâm lý của bệnh nhân thông qua tri thức y khoa thường thức sạch.- **Sản sinh dòng Lead chất lượng cao (Lead Generation):** Thu nạp nguồn dữ liệu (Data) khách hàng có nhu cầu can thiệp thật, tỷ lệ chuyển đổi cao thay vì số lượng inbox ảo.- **Tối ưu hóa chỉ số Authority chuyên gia:** Đẩy cao vị thế y đức và năng lực lâm sàng của Bác sĩ Vinh trên toàn bộ không gian số.- **Nuôi dưỡng Media Network vô tận:** Vận hành trơn tru guồng quay sản xuất nội dung đa kênh (TikTok, Website, Fanpage) mà không bị rơi vào trạng thái đói ý tưởng.- **Số hóa kho tài sản niềm tin (Trust Assets):** Liên tục đóng gói, chuẩn hóa kho dữ liệu Case Study thành công và Review thực tế để làm đạn dược truyền thông.- **Pre-warming (Làm ấm khách trước khi gặp Sales):** Giáo dục khách hàng hiểu đúng về phác đồ và giá trị dịch vụ, hỗ trợ *Sales OS* nâng tỷ lệ chốt ca lâm sàng lớn lên mức tối đa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9f51ab72-2db4-4e5a-a471-8b0782ebcdef','26-marketing-os',NULL,2,'24.2 Phạm vi quản trị toàn diện','242-pham-vi-quan-tri-toan-dien',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('987f3de5-8ab8-44a4-912d-101128833d52','9f51ab72-2db4-4e5a-a471-8b0782ebcdef',4,'text','Marketing OS chịu trách nhiệm quản lý toàn bộ các điểm chạm truyền thông đầu phễu và tài sản nội dung số của nha khoa, bao gồm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2c1c8250-c3cf-44d8-bea7-8fe147df8001','9f51ab72-2db4-4e5a-a471-8b0782ebcdef',5,'text','- **Thương hiệu cá nhân (Personal Brand):** Định hướng nội dung, phong cách sống và góc nhìn chuyên môn của Bác sĩ Founder.- **Mạng lưới truyền thông (Media Network):** Kênh phân phối đa nền tảng (TikTok, Facebook, YouTube, Zalo OA).- **Lịch biên tập (Content Calendar):** Ma trận nội dung phân tầng phối hợp nhịp nhàng hằng tháng.- **Kịch bản sản xuất (Video Scripts):** Kho kịch bản video ngắn, video dài chuẩn hóa kiến thức y khoa thường thức.- **Chiến dịch quảng cáo (Ads Campaigns):** Kỹ thuật thiết lập và tối ưu hóa ngân sách quảng cáo Paid Ads.- **Hạ tầng số vệ tinh:** Website, Google Business Profile, Bản đồ hiển thị SEO/GEO.- **Hồ sơ chứng cứ:** Thư viện Case Study Before/After, Thư viện Review 5 sao thực tế từ cộng đồng.- **Điểm chạm tương tác trực tiếp:** Sự kiện Livestream, Webinar giải đáp y khoa trực tuyến hằng tuần.- **Lead Tracking System:** Hệ thống mã hóa và theo dõi chính xác nguồn gốc đổ về của từng Lead.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a7d98883-96f2-4c6e-8306-40326d29d2d0','26-marketing-os',NULL,2,'24.3 Quy trình lõi 8 bước điều hành truyền thông đa kênh','243-quy-trinh-loi-8-buoc-ieu-hanh-truyen-thong-a-kenh',2,'[]');
