INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8b84d70e-a693-4197-bb13-0ef3b471f7bb','26-marketing-os',NULL,2,'25.4 Đội ngũ thực thi và sơ đồ phối hợp phòng ban','254-oi-ngu-thuc-thi-va-so-o-phoi-hop-phong-ban',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('14bf4615-66e9-4e0a-880a-e50d3136fa42','8b84d70e-a693-4197-bb13-0ef3b471f7bb',32,'text','- **Nhân sự chịu trách nhiệm chính (Owner):** Marketing Lead / Growth Lead. Đây là người chịu chỉ tiêu trực tiếp về sản lượng Lead nóng và tối ưu hóa chỉ số chi phí sắm khách (CAC).- **Đội ngũ phối hợp thực thi (Contributors):** Bác sĩ(Cung cấp chuyên môn), Designer (Thiết kế ấn phẩm), Editor (Dựng video), Ads Specialist (Tối ưu quảng cáo), Sales Team (Phản hồi chất lượng Lead) và Data Team (Đồng bộ mã nguồn theo dõi).',NULL,NULL,NULL,NULL,NULL);
