INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e1cd33a3-70f6-4710-8f44-854d37f43704','b9477b47-fa5f-424b-9eb2-d6ff2a233ace',33,'text','Dashboard điều hành của Marketing OS bóc tách chi tiết các chỉ số đo lường từ tầng hiển thị diện rộng cho đến hiệu quả chuyển đổi tài chính cuối cùng:',NULL,NULL,NULL,NULL,NULL);
