INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('904155ca-f533-4c1a-aaea-11029e1bd85d','26-marketing-os',NULL,2,'24.6 Bộ đầu ra tài liệu tiêu chuẩn (Deliverables Bundle)','246-bo-au-ra-tai-lieu-tieu-chuan-deliverables-bundle',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d50c2a69-9ffb-427e-8036-693d93a43ae5','904155ca-f533-4c1a-aaea-11029e1bd85d',35,'text','Để phân hệ Marketing OS được nghiệm thu hoàn tất và lưu trữ thành tài sản mã nguồn vận hành của nha khoa, đội ngũ tiếp thị bắt buộc phải đóng gói thành công bộ 11 tài liệu kỹ thuật sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8e699f9b-4d35-4739-8059-7095b533d3df','904155ca-f533-4c1a-aaea-11029e1bd85d',36,'text','- **1. Marketing OS Playbook:** Cuốn cẩm nang quy định toàn bộ tiêu chuẩn SLA vận hành tiếp thị, tông giọng thương hiệu và quy trình phối hợp phòng ban.- **2. Omnichannel Channel Map:** Bản đồ cấu trúc phân tầng vai trò của từng kênh truyền thông xã hội.- **3. Content Pillar System:** Tài liệu định hình các trục nội dung cốt lõi được bảo chứng y khoa bởi Bác sĩ Vinh.- **4. Monthly Content Calendar:** File Master lập lịch chi tiết ngày phát sóng, chủ đề, định dạng bài viết đa kênh hằng tháng.- **5. Video Script Library:** Thư viện chứa ít nhất 50 kịch bản video ngắn chuẩn cấu trúc giữ chân người xem trong 3 giây đầu.- **6. Ads Campaign Plan:** Bản kế hoạch phân bổ ngân sách quảng cáo, cấu trúc chiến dịch và ma trận bài mẫu (Ad Creatives).- **7. SEO / GEO Keyword Map:** Bản đồ bộ từ khóa chuẩn y khoa thường thức được tối ưu hóa theo hành vi tìm kiếm của cư dân địa phương.- **8. Google Business Profile Checklist:** Bộ quy chuẩn tối ưu hóa hình ảnh phòng khám, cập nhật giờ làm việc và quy trình phản hồi đánh giá khách hàng.- **9. LTV & Lead Source Tracker System:** Hệ thống mã hóa link UTM để đo lường chính xác nguồn đổ về của dòng tiền mặt.- **10. Central Case Library:** Kho lưu trữ hình ảnh/video lâm sàng Before/After đã được bệnh nhân ký biên bản đồng ý truyền thông.- **11. Review Library & Trust Asset Checklist:** Tập hợp các ảnh chụp feedback, review 5 sao và danh mục tài liệu cẩm nang giáo dục (File 101 - 1010) sẵn sàng hỗ trợ Sales OS.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a618d451-0f19-4fe0-8742-4d74fa9ffd1e','904155ca-f533-4c1a-aaea-11029e1bd85d',37,'text','**Mantra tối thượng của Marketing OS:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('56fabad5-eb60-4f6e-8ab9-1b2e79d8e329','904155ca-f533-4c1a-aaea-11029e1bd85d',38,'text','*"Đừng cố gắng bán dịch vụ nha khoa cho một thị trường đang hoài nghi. Hãy dùng tri thức sạch để giáo dục và sưởi ấm nhận thức của họ. Khi bạn cho đi giá trị y khoa đủ lớn, Marketing sẽ không còn là một hoạt động chèo kéo tốn tiền, mà trở thành lời mời gọi tử tế đưa bệnh nhân bước vào bộ tộc nụ cười của phòng khám."*',NULL,NULL,NULL,NULL,NULL);
