INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('83fcbfb4-6b15-49ef-a604-81a8e1842798','f3092b4b-84b9-460e-8ae4-9eccae8bf59f',40,'image',NULL,'book/26-marketing-os/08e823dc-8366-48f1-a246-31a88d22a1f0-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6301efc3-c7b0-4f16-82cf-70073edde099','26-marketing-os','f3092b4b-84b9-460e-8ae4-9eccae8bf59f',3,'MODULE 1: BRANDq STRATEGY - ĐỊNH VỊ THƯƠNG HIỆU VÀ GỐC RỄ NIỀM TIN Y KHOA','module-1-brandq-strategy-inh-vi-thuong-hieu-va-goc-re-niem-tin-y-khoa',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('227fbe06-2553-4299-a3a6-2e97dd3561e6','6301efc3-c7b0-4f16-82cf-70073edde099',41,'text','Trong cấu trúc tổng thể của *Marketing OS*, phân hệ **Brand Strategy (Chiến lược Thương hiệu)** đóng vai trò là cột tủy sống định hình toàn bộ các biểu hiện truyền thông phía sau. Nhiều chủ phòng khám thường nhầm lẫn chiến lược thương hiệu với việc thiết kế một logo đẹp hay chọn màu sắc biển hiệu. Đó chỉ là lớp vỏ bọc bề ngoài.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf1218e1-5e12-4c67-966d-08291682c6f6','6301efc3-c7b0-4f16-82cf-70073edde099',42,'text','Bản chất của Chiến lược Thương hiệu trong ngành y tế là **Xác lập rào cản nhận thức và quy hoạch lòng tin**. Bệnh nhân không bao giờ bước vào một phòng khám nha khoa chỉ vì nơi đó treo biển giảm giá rẻ nhất. Ngược lại, việc phá giá vô tội vạ chỉ kích hoạt bộ lọc phòng thủ, khiến khách hàng nghi ngờ về chất lượng vật liệu và tay nghề lâm sàng của Bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9b1018f4-eee9-465d-8c09-d9926012b1c8','6301efc3-c7b0-4f16-82cf-70073edde099',43,'text','Hành vi xuống tiền của bệnh nhân luôn được chi phối bởi **5 Mỏ neo Niềm tin** cốt lõi hằng ngày:',NULL,NULL,NULL,NULL,NULL);
