INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b3949680-8f5b-47fb-b17b-988e2058b66b','3c6a8802-5194-45b2-94ef-76c3abcbeaff',58,'text','Để phân hệ Brand Strategy được nghiệm thu hoàn tất và đóng dấu lưu trữ vào tài sản mã nguồn vận hành của hệ điều hành, đội ngũ thực thi bắt buộc phải đóng gói thành công bộ 6 tài liệu kỹ thuật sau:',NULL,NULL,NULL,NULL,NULL);
