INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3942cab7-c860-4071-bbc0-f3cfe20b7cc0','3c6a8802-5194-45b2-94ef-76c3abcbeaff',60,'text','Văn bản khóa chặt vị thế độc bản của phòng khám, được cấu trúc theo công thức toán học quản trị:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aeeebadb-ddc6-4642-8740-93750ade2c3a','3c6a8802-5194-45b2-94ef-76c3abcbeaff',61,'text','\\text{Định vị độc bản} = \\text{Tệp khách hàng mục tiêu} + \\text{Dịch vụ mũi nhọn} + \\text{Giá trị thực chứng khác biệt}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f19699b5-110c-487c-9831-300d0e795727','3c6a8802-5194-45b2-94ef-76c3abcbeaff',62,'image',NULL,'book/26-marketing-os/326534f3-3bff-4d30-b721-d48429c3fb40-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2680286a-4e2c-4bc5-ae8a-0abd4f73c55e','3c6a8802-5194-45b2-94ef-76c3abcbeaff',63,'text','**3.2 Hồ sơ Chân dung Bệnh nhân Mục tiêu (Customer Avatar Sheet)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('40e20ff2-4700-41a1-b659-1b1d85f5b73f','3c6a8802-5194-45b2-94ef-76c3abcbeaff',64,'text','Không vẽ chân dung khách hàng chung chung theo độ tuổi. Hồ sơ bắt buộc phải bóc tách dữ liệu thành 3 trường thông tin tầng sâu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f01cedc8-348b-4374-a89a-ee2424cd33a4','3c6a8802-5194-45b2-94ef-76c3abcbeaff',65,'text','- **Trường hành vi & Thu nhập:** Nhóm người làm văn phòng, chủ doanh nghiệp hoặc trung niên có ý thức bảo vệ sức khỏe, sở hữu mức thu nhập ổn định, sẵn sàng chi trả cho các giải pháp y khoa chất lượng cao nếu được chứng minh minh bạch.- **Trường nỗi đau sinh học:** Sợ đau khi chạm vào ghế nha, hoang mang trước các chi phí ẩn phát sinh, lo lắng về biến chứng đào thải Implant hoặc chạy răng hậu chỉnh nha.- **Trường rào cản quyết định:** Thiếu tri thức thường thức chuẩn xác, dễ bị nhiễu loạn thông tin bởi các quảng cáo bẩn phá giá trên thị trường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3369734a-3025-4297-9b18-493909c5d9bb','3c6a8802-5194-45b2-94ef-76c3abcbeaff',66,'text','**3.3 Danh sách Dịch vụ Ưu tiên (Priority Service Map)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bc77877e-da3c-40d5-bd95-d74bd00d7fc5','3c6a8802-5194-45b2-94ef-76c3abcbeaff',67,'text','Quy hoạch rõ ràng nguồn lực tài chính và công nghệ, phân tách danh mục dịch vụ thành 3 phân tầng thực chiến:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4f16e870-1883-4d44-a0f7-0e7f22b2e308','3c6a8802-5194-45b2-94ef-76c3abcbeaff',68,'text','- **Dịch vụ thu hút (Magnet Services):** Cạo vôi răng siêu âm tầm soát, nhổ răng khôn không đau bằng máy Piezotome, tẩy trắng răng công nghệ cao. Mục tiêu: Thu hút traffic sạch, nạp data vào Patient OS.- **Dịch vụ chủ lực (Core Services):** Chỉnh nha tăng trưởng/Invisalign, cấy ghép Implant đơn lẻ đến toàn hàm (All-on-X). Mục tiêu: Kích nổ doanh thu lớn, khẳng định uy tín chuyên gia của Bác sĩ Vinh.- **Dịch vụ đặc quyền (Premium Services):** Răng sứ thẩm mỹ cao cấp bảo tồn tối đa mô răng thật, phục hình trên thanh Bar công nghệ cao. Mục tiêu: Gia tăng chỉ số LTV tối đa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4da4220a-b945-425e-a691-06a2962a0784','3c6a8802-5194-45b2-94ef-76c3abcbeaff',69,'text','**3.4 Thông điệp Thương hiệu Chính (Core Brand Message)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7292e5de-cc09-4c2f-9c95-c91f58a16f9d','3c6a8802-5194-45b2-94ef-76c3abcbeaff',70,'text','Slogan cốt lõi xuyên suốt mọi chiến dịch, xuất hiện đồng bộ trên website, ảnh bìa Media Network và các ấn phẩm trao tay bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('167d76cc-c836-40a2-8876-fa8c3d3b89d2','3c6a8802-5194-45b2-94ef-76c3abcbeaff',71,'text','**3.5 Bộ Cột trụ Nội dung Hệ thống (Content Pillar System)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4c096d24-1585-4fcc-884b-aee64da86d2e','3c6a8802-5194-45b2-94ef-76c3abcbeaff',72,'text','Thiết lập 4 trục nội dung sạch, triệt tiêu hoàn toàn tình trạng đăng bài ngẫu hứng, rời rạc hằng tuần:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1fe5147d-d8d9-40eb-8f58-b24cc7de9d45','3c6a8802-5194-45b2-94ef-76c3abcbeaff',73,'text','- **Pillar 1 - Chuyên gia lâm sàng (Clinical Authority):** Các video Bác sĩ Vinh trực tiếp phân tích phim chụp CT Cone Beam, giải thích cơ chế tích hợp xương của trụ Implant hoặc tiến trình di chuyển răng chỉnh nha.- **Pillar 2 - Câu chuyện người thật (Clinical Storytelling):** Đóng gói hành trình lột xác diện mạo, tìm lại chức năng ăn nhai của những cựu bệnh nhân.- **Pillar 3 - Giáo dục thường thức (Patient Education):** Bóc tách các sai lầm tai hại hằng ngày của người dân (dùng tăm tre, tự mua kem đánh răng trôi nổi, lười đi recall định kỳ).- **Pillar 4 - Trải nghiệm thực địa (Behind the Scenes):** Thước phim unboxing quy trình hấp sấy vô trùng khép kín, không gian sảnh chờ đón tiếp chuẩn 5 sao để mỏ neo cảm xúc an toàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0840e42-89d3-4c7d-8015-88aced4f86a1','3c6a8802-5194-45b2-94ef-76c3abcbeaff',74,'text','**3.6 Guideline Giọng nói Thương hiệu (Brand Tone of Voice)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('735fe6b9-2857-434f-bee5-8d0b54320fc9','3c6a8802-5194-45b2-94ef-76c3abcbeaff',75,'text','Quy định nghiêm ngặt tông giọng phát ngôn của toàn bộ nhân sự sàn lẫn nhân sự viết nội dung số trên không gian mạng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('25610faa-0156-44a2-8db3-8682379f255c','3c6a8802-5194-45b2-94ef-76c3abcbeaff',76,'text','- **Thấu cảm & Tử tế (Empathetic):** Luôn lắng nghe, gọi tên riêng của bệnh nhân, thấu thấu nỗi sợ đau sinh học của họ để dùng ngôn từ bao bọc, xoa dịu. Tuyệt đối không dùng giọng bề trên, phán xét hay hù dọa bệnh nhân để ép sale.- **Chuyên nghiệp & Minh bạch (Authoritative & Transparent):** Nói chuyện dựa trên bằng chứng dữ liệu hình ảnh khoa học. Giải thích phác đồ bằng ngôn từ bình dân dễ hiểu nhưng đạt độ chuẩn xác y khoa tuyệt đối. Minh bạch chi phí trọn gói ngay từ đầu, không mập mờ chi phí ẩn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf2da746-22a1-437d-bf9d-1ffd6d7cdd62','3c6a8802-5194-45b2-94ef-76c3abcbeaff',77,'text','**Mantra điều hành Phân hệ:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('232a4e8b-eb99-46ae-bf1d-5cfbd86a13ba','3c6a8802-5194-45b2-94ef-76c3abcbeaff',78,'text','*"Thương hiệu nha khoa không được xây nên từ những tấm biển quảng cáo lấp lánh ngoài đường mặt phố, nó được định vị chắc chắn trong tâm trí bệnh nhân bằng sự tử tế y khoa được chuẩn hóa nhất quán qua mọi điểm chạm truyền thông hằng ngày."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9eac6ff5-842e-45c0-95e4-d38bf9674b9c','26-marketing-os','f3092b4b-84b9-460e-8ae4-9eccae8bf59f',3,'MODULE 2: CONTENT ENGINE - DÂY CHUYỀN SẢN XUẤT NỘI DUNG SỐ VÀ CỐT LÕI GIÁO DỤC BỆNH NHÂN','module-2-content-engine-day-chuyen-san-xuat-noi-dung-so-va-cot-loi-giao-duc-benh',11,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('741a60e5-fc5e-4a5e-bfa3-b7a8f53f79ee','26-marketing-os','9eac6ff5-842e-45c0-95e4-d38bf9674b9c',5,'Định nghĩa và tư duy cốt lõi: triệt tiêu cảm hứng, số hóa nhà máy nội dung','inh-nghia-va-tu-duy-cot-loi-triet-tieu-cam-hung-so-hoa-nha-may-noi-dung',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('205e6dbc-75e0-442f-8dff-e599c23bec93','741a60e5-fc5e-4a5e-bfa3-b7a8f53f79ee',79,'text','Sai lầm lớn nhất của 95% các phòng khám nha khoa hiện nay khi làm truyền thống là vận hành nội dung theo **Hội chứng cảm hứng**. Hôm nay Bác sĩ vui thì quay một video, ngày mai nhân viên marketing hứng lên thì viết một bài bài viết chắp vá, tuần sau bận rộn lâm sàng thì bỏ bẵng kênh truyền thông dẫn đến tình trạng "chết lâm sàng" trên không gian số. Cách làm này không những đốt cháy ngân sách nhân sự mà còn khiến bộ lọc thuật toán của các nền tảng bóp nghẹt lượt tiếp cận tự nhiên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3e52a85-51f1-4d99-8769-e4f455b69a6c','741a60e5-fc5e-4a5e-bfa3-b7a8f53f79ee',80,'text','Trong hệ điều hành **Dental Empire OS**, chúng tôi định nghĩa lại: **Content không phải là một tác phẩm nghệ thuật làm theo cảm xúc, Content là một dây chuyền sản xuất công nghiệp có biên độ dữ liệu chuẩn hóa.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4fc186e-0db2-4a59-8889-1e10597aba52','741a60e5-fc5e-4a5e-bfa3-b7a8f53f79ee',81,'text','Tại phân hệ **Content Engine**, nội dung sạch được ví như dòng máu nuôi dưỡng toàn bộ hệ sinh thái tiếp thị đầu phễu. Quy trình sản xuất được thiết lập như một nhà máy khép kín: Nhập nguyên liệu thô từ phòng điều trị, đưa qua dây chuyền chế biến (Biên soạn kịch bản, quay dựng chuẩn hóa), và xuất xưởng thành hàng loạt điểm chạm truyền thông có độ phủ cao nhằm mục đích tối hậu là tự động giáo dục nhận thức và sàng lọc lead nóng cho hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('db4c013a-055b-498f-9dd5-cb1892b113f9','26-marketing-os','9eac6ff5-842e-45c0-95e4-d38bf9674b9c',5,'Luồng vận hành tuyến tính 9 bước của content engine','luong-van-hanh-tuyen-tinh-9-buoc-cua-content-engine',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('27a931d3-8577-4ac3-ae76-1e39340bbfe3','db4c013a-055b-498f-9dd5-cb1892b113f9',82,'text','Mỗi một ý tưởng khi xuất hiện bắt buộc phải di chuyển nghiêm ngặt qua trục dọc 9 bước của đường ống sản xuất dưới đây để tối ưu hóa năng suất và triệt tiêu mọi sự lãng phí tài nguyên chất xám:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a1e42ae-c666-426a-bcd4-8fb0d2046e3b','db4c013a-055b-498f-9dd5-cb1892b113f9',83,'image',NULL,'book/26-marketing-os/13e7e14b-8d28-4258-8b69-c47fa06b5034-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('507719b2-389d-4b4d-9b9d-428eecf82fbb','26-marketing-os','9eac6ff5-842e-45c0-95e4-d38bf9674b9c',5,'Ma trận 8 cột trụ nội dung chiến lược (content pillars matrix)','ma-tran-8-cot-tru-noi-dung-chien-luoc-content-pillars-matrix',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7907eb6-9eea-4d6d-b363-f957e2a8383e','507719b2-389d-4b4d-9b9d-428eecf82fbb',84,'text','Để đảm bảo dòng thác thông tin phát sóng đa kênh luôn giữ vững tính cân bằng giữa giá trị y đức tử tế và mục tiêu tăng trưởng doanh thu, *Content Engine* quy hoạch nội dung thành 8 trục cốt lõi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b79f770d-77e6-44c2-a7e6-9f7cbe3e8a2c','507719b2-389d-4b4d-9b9d-428eecf82fbb',85,'image',NULL,'book/26-marketing-os/ff348993-fd02-42a0-a559-be64312583db-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('eae4559b-de44-4515-83bb-8d26a473946a','26-marketing-os','9eac6ff5-842e-45c0-95e4-d38bf9674b9c',5,'Bộ đầu ra tài liệu tiêu chuẩn đóng gói (Deliverables Bundle)','bo-au-ra-tai-lieu-tieu-chuan-ong-goi-deliverables-bundle',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f248846b-9570-4e65-b52a-dd5c598cafe3','eae4559b-de44-4515-83bb-8d26a473946a',86,'text','Toàn bộ hoạt động của phân hệ Content Engine bắt buộc phải được "vật chất hóa" thành bộ 8 tài sản hữu hình, sẵn sàng bàn giao cho nhân sự vận hành hằng ngày:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c2a2eade-6c13-46ab-8afa-7cdcfec6d0a5','eae4559b-de44-4515-83bb-8d26a473946a',87,'text','- **Monthly Content Calendar:** File Master lập lịch chi tiết ngày giờ phát sóng, tiêu đề bài viết, mã kịch bản và phân tầng phân nhiệm nhân sự chịu trách nhiệm đa kênh trọn tháng.- **Central Idea Bank:** Ngân hàng lưu trữ ít nhất 200 ý tưởng nội dung thô, liên tục được cập nhật từ các câu hỏi thực tế của bệnh nhân tại ghế nha và dữ liệu tìm kiếm của thị trường.- **Video Script Library:** Thư viện chứa các file kịch bản chữ viết chi tiết cho video ngắn (TikTok/Reels) và video dài (YouTube), quy định rõ lời thoại Bác sĩ, góc máy quay và hiệu ứng âm thanh tương ứng.- **Video Production Checklist:** Bảng kiểm tra tiêu chuẩn kỹ thuật trước khi bấm máy (Tiêu chuẩn ánh sáng phòng khám, chất lượng âm thanh micro cài áo, trang phục blouse Bác sĩ sạch sẽ chuẩn y đức).- **Case Content Template:** Biểu mẫu cấu trúc viết bài Storytelling cho ca lâm sàng Before/After, dẫn dắt cảm xúc người đọc từ trạng thái đồng cảm nỗi đau đến trạng thái Wow Peak khi nhìn thấy kết quả.- **FAQ Content Specification:** Tập hợp bộ văn bản câu trả lời chuẩn hóa cho các câu hỏi thường gặp, đảm bảo toàn bộ nhân sự viết bài lẫn nhân sự trực inbox đồng bộ 100% tri thức.- **Content Repurpose Plan:** Bản thiết kế ma trận nhân bản tài sản số, quy định công thức bóc tách từ một nội dung gốc dài thành nhiều định dạng bài viết, checklist, ảnh ngắn đa kênh.- **Weekly Content Report Template:** Biểu mẫu báo cáo định lượng hằng tuần hiển thị các chỉ số Reach, View, Watch time, số lượng Lead sản sinh từ nội dung để báo cáo lên ban giám đốc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f3b4ce14-cf04-4b89-9a2c-84ca7a13bf69','26-marketing-os','9eac6ff5-842e-45c0-95e4-d38bf9674b9c',5,'Mỏ neo kỹ thuật: sức mạnh nhân bản và chỉ số ROI nội dung','mo-neo-ky-thuat-suc-manh-nhan-ban-va-chi-so-roi-noi-dung',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d1143202-5ab3-49ac-8b8b-1b2f147722e7','f3b4ce14-cf04-4b89-9a2c-84ca7a13bf69',88,'text','Để định lượng chính xác hiệu quả kinh tế của dây chuyền sản xuất nội dung số, hệ điều hành *Data OS* cấu hình công thức toán học đo lường **Hiệu suất Nhân bản Tài sản (Asset Multiplier Index)** dựa trên tỷ lệ chuyển đổi từ một tài sản gốc ban đầu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6f6fde1b-13b8-4d09-a4fb-f96d5f610886','f3b4ce14-cf04-4b89-9a2c-84ca7a13bf69',89,'text','\\text{Asset Multiplier Index} = \\frac{\\text{Tổng số điểm chạm thứ cấp tạo ra}}{\\text{Số lượng tài sản gốc đầu vào}}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7c84a843-c505-4204-a187-bda6c782eb0a','f3b4ce14-cf04-4b89-9a2c-84ca7a13bf69',90,'text','*Ví dụ thực tế:* Từ 1 buổi Workshop chuyên sâu dài 90 phút của Bác sĩ Vinh (1 tài sản gốc), đội ngũ marketing bóc tách thành 1 video YouTube dài, 10 video ngắn TikTok, 5 bài viết Fanpage, 3 bài blog SEO cho, 1 file checklist PDF và 1 luồng tin nhắn Zalo OA. Chỉ số nhân bản đạt mốc \\frac{21}{1} = 21 điểm chạm. Đây chính là động cơ vĩnh cửu giúp phòng khám tự chủ 100% nguồn tài nguyên nội dung sạch mà không bao giờ bị rơi vào trạng thái đói ý tưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a6b0f654-6db3-4e4b-91ba-8e4e7d448261','f3b4ce14-cf04-4b89-9a2c-84ca7a13bf69',91,'text','**Mantra tối thượng của Content Engine:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6422cd33-1e04-48c3-a357-efd2e9bd4277','f3b4ce14-cf04-4b89-9a2c-84ca7a13bf69',92,'text','*"Đừng đợi đến khi có cảm hứng mới sản xuất nội dung. Hãy vận hành thương hiệu nha khoa của bạn như một tòa soạn báo chuyên nghiệp và tử tế, nơi tri thức y khoa được xuất xưởng đều đặn mỗi ngày để bao bọc, hướng dẫn và sưởi ấm niềm tin của hàng triệu khách hàng."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('48ab3cbf-e2ab-4930-8fdb-02baef3b9807','26-marketing-os','f3092b4b-84b9-460e-8ae4-9eccae8bf59f',3,'MODULE 3: CHANNEL SYSTEM - MẠNG LƯỚI PHÂN PHỐI ĐA KÊNH VÀ QUY HOẠCH ĐIỂM CHẠM TRUYỀN THÔNG','module-3-channel-system-mang-luoi-phan-phoi-a-kenh-va-quy-hoach-iem-cham-truyen-',17,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6d37dc0d-33bd-4ef8-80ee-fda3b691167f','26-marketing-os','48ab3cbf-e2ab-4930-8fdb-02baef3b9807',5,'3.1  Định nghĩa và tư duy cốt lõi: triệt tiêu đồng đồng hóa, phân định nhiệm vụ nền tảng','31-inh-nghia-va-tu-duy-cot-loi-triet-tieu-ong-ong-hoa-phan-inh-nhiem-vu-nen-tang',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('db9f65e7-479f-4cb6-9150-cc7a798a2a30','6d37dc0d-33bd-4ef8-80ee-fda3b691167f',93,'text','Một trong những sai lầm lười biếng và phổ biến nhất của các phòng khám nha khoa hiện nay khi làm truyền thông là **Đồng hóa kênh phân phối** — tức là sản xuất ra một nội dung và đăng tải y nguyên một định dạng đó lên tất cả các nền tảng từ TikTok, Facebook cho đến Website. Họ đăng một video ngắn 30 giây của TikTok lên YouTube dài, hoặc copy một bài viết học thuật thô cứng của Website để dán vào bài viết Facebook.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a31adf0d-5896-4c61-9bd4-9a5178248bc8','6d37dc0d-33bd-4ef8-80ee-fda3b691167f',94,'text','Cách làm này trực tiếp vi phạm thuật toán phân phối của các nền tảng số, làm lãng phí tài nguyên nội dung và bẻ gãy trải nghiệm tự nhiên của người dùng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3aa0be73-319c-4e4b-aac7-0153fcaa0753','6d37dc0d-33bd-4ef8-80ee-fda3b691167f',95,'text','Trong hệ điều hành **Dental Empire OS**, chúng tôi thiết lập tư duy: **Kênh phân phối không phải là nơi chứa nội dung ngẫu nhiên, Kênh phân phối là một mắt xích có nhiệm vụ biệt lập trên Hành trình bệnh nhân (Patient Journey).**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bb035f9b-3b9d-4325-a1fd-34064bdc92f8','6d37dc0d-33bd-4ef8-80ee-fda3b691167f',96,'text','Tại nha khoa **Thích Làm Răng**, phân hệ **Channel System** chịu trách nhiệm quy hoạch, định tuyến và tối ưu hóa từng nền tảng truyền thông theo đúng đặc tính hành vi của người dùng tại kênh đó. Nội dung có thể chung một gốc tri thức từ Bác sĩ Nguyễn Phước Vinh, nhưng khi xuất xưởng qua các kênh, chúng bắt buộc phải khoác lên mình những "bộ trang phục" định dạng hoàn toàn khác nhau để tối ưu hóa năng lực tiếp cận và tỷ lệ chuyển đổi đầu phễu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('77ad2464-f51d-4159-b032-8276a8a64a72','26-marketing-os','48ab3cbf-e2ab-4930-8fdb-02baef3b9807',5,'3.2 Ma trận vai trò từng kênh trong hệ sinh thái nha khoa','32-ma-tran-vai-tro-tung-kenh-trong-he-sinh-thai-nha-khoa',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4ac04ac4-bcc1-4444-83d6-003ac4708498','77ad2464-f51d-4159-b032-8276a8a64a72',97,'text','Để quản trị dòng chảy thông tin không bị chồng chéo, Channel System phân định rõ ràng vai trò chiến lược, định dạng chủ lực và chỉ số đo lường cho 6 kênh huyết mạch hằng ngày:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('553a6f86-09ae-42d8-8f94-739330a243ba','77ad2464-f51d-4159-b032-8276a8a64a72',98,'image',NULL,'book/26-marketing-os/96c7f336-7297-4cbd-abc7-434457107d41-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('145583db-e17b-4df7-ac23-0cedf905ddec','26-marketing-os','48ab3cbf-e2ab-4930-8fdb-02baef3b9807',5,'3.3 Nguyên tắc phân phối đa kênh &amp; kỹ thuật tái cấu trúc định dạng (Repurposing engine)','33-nguyen-tac-phan-phoi-a-kenh-amp-ky-thuat-tai-cau-truc-inh-dang-repurposing-en',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d734eb70-dafc-40d6-abe1-dc0e8f2fba05','145583db-e17b-4df7-ac23-0cedf905ddec',99,'text','Quy tắc vận hành tối cao của Channel System: **Một nội dung sạch không bao giờ được phép chết sau một lần đăng tải. Nó phải được vụn hóa và tái sinh liên tục trên toàn bộ mạng lưới truyền thông.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c02d1e7e-890f-4a09-b556-92a9fded330c','145583db-e17b-4df7-ac23-0cedf905ddec',100,'text','Khi Bác sĩ hoàn thiện một tài sản nội dung gốc (Ví dụ: Một video 15 phút giải thích phác đồ: *"Mất răng lâu năm tiêu xương hàm có cấy Implant được không?"*), cỗ máy Repurposing Engine của phòng khám sẽ tự động bóc tách thành các định dạng vệ tinh bao bọc toàn bộ không gian số hằng tuần:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f2387ff4-cc93-4f35-8732-eb546f4998b9','145583db-e17b-4df7-ac23-0cedf905ddec',101,'image',NULL,'book/26-marketing-os/ce91196d-cf32-4256-9f22-a95ca41adf4d-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b74f7ef-4417-4c88-bd44-afb313528613','145583db-e17b-4df7-ac23-0cedf905ddec',102,'text','Tiêu chuẩn kỹ thuật khi phân phối (Distribution SLA):',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3820723-0b72-4c9e-b5f3-9520477d69db','145583db-e17b-4df7-ac23-0cedf905ddec',103,'text','- **Tuyệt đối không dính Watermark:** Video khi đăng chéo giữa các nền tảng bắt buộc phải xóa logo của nền tảng gốc.- **Native Optimization:** Bài viết trên nền tảng nào phải tuân thủ chuẩn kích thước ảnh, độ dài văn bản và hệ thống Hashtag tối ưu của riêng nền tảng đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f6e9e886-0528-492c-8777-3fb73d649190','26-marketing-os','48ab3cbf-e2ab-4930-8fdb-02baef3b9807',5,'3.4 Bộ đầu ra tài liệu tiêu chuẩn đóng gói (Deliverables Bundle)','34-bo-au-ra-tai-lieu-tieu-chuan-ong-goi-deliverables-bundle',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1e051977-6330-4213-bca3-d6436f6c2b43','f6e9e886-0528-492c-8777-3fb73d649190',104,'text','Để phân hệ Channel System được nghiệm thu hoàn tất và đưa vào vận hành tự động hằng ngày, khối tiếp thị bắt buộc phải hoàn thiện bộ 5 tài sản quản trị sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8b7ae268-7fb2-4ca2-a5e5-81fa55627fe4','f6e9e886-0528-492c-8777-3fb73d649190',105,'text','- **Omnichannel Channel Map:** Bản đặc tả kỹ thuật quy định rõ vai trò, mục tiêu, phân tầng tệp khách hàng và liên kết API dữ liệu giữa các kênh về hệ thống CRM trung tâm.- **Posting Schedule & Calendar System:** Bảng thiết lập khung giờ vàng phát sóng cố định cho từng nền tảng (Ví dụ: TikTok đăng lúc 11:30 và 20:00 hằng ngày; Zalo OA nhắc lịch tự động vào 9:00 sáng).- **Platform Optimization Checklist:** Bộ quy chuẩn tối ưu hóa hạ tầng kỹ thuật cho từng kênh (Tiêu chuẩn ảnh bìa Fanpage, cấu trúc Bio TikTok, bộ từ khóa thẻ Tag YouTube, kỹ thuật geo-tagging cho Google Maps).- **Content Repurpose Script Checklist:** Bản hướng dẫn kỹ thuật bóc tách nội dung dành cho nhân sự Editor và Copywriter, quy định công thức chuyển đổi từ video dài sang định dạng ngắn và văn bản.- **Channel Performance Report Dashboard:** Mẫu báo cáo trích xuất số liệu hằng tuần nhằm đánh giá chính xác kênh nào đang mang lại hiệu quả kinh tế (ROI) cao nhất và kênh nào đang bị nghẽn đường ống dữ liệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4b62b628-ef20-4056-82dd-edd3d67ce175','26-marketing-os','48ab3cbf-e2ab-4930-8fdb-02baef3b9807',5,'3.5 Mỏ neo chiến lược: chỉ số sức khỏe phân phối (Distribution Health Index)','35-mo-neo-chien-luoc-chi-so-suc-khoe-phan-phoi-distribution-health-index',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f2612808-166c-4df5-aa9c-1c0c761a70e5','4b62b628-ef20-4056-82dd-edd3d67ce175',106,'text','Nhà quản trị kiểm soát chất lượng vận hành của Channel System thông qua công thức toán học đo lường **Chỉ số bao phủ điểm chạm (Omnichannel Coverage Score)** hằng tháng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7e53fb05-aac0-44b1-807e-8fa282d45a99','4b62b628-ef20-4056-82dd-edd3d67ce175',107,'text','\\text{Omnichannel Coverage Score} = \\frac{\\text{Số lượng nền tảng đạt mục tiêu tăng trưởng tối thiểu}}{\\text{Tổng số lượng kênh vận hành trong hệ sinh thái}}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2924f048-7ac0-43a2-90d3-0e35c335404b','4b62b628-ef20-4056-82dd-edd3d67ce175',108,'text','Mục tiêu tiêu chuẩn của phòng khám là đạt chỉ số S \\ge 85\\%. Điều này đảm bảo thương hiệu của bạn không phụ thuộc vào một kênh duy nhất. Nếu thuật toán TikTok thay đổi, phòng khám vẫn đứng vững nhờ pháo đài SEO Website và luồng khách local ổn định từ Google Business Profile.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8ab8b9c0-fe1f-4192-a5d4-ed3e6b473e2a','4b62b628-ef20-4056-82dd-edd3d67ce175',109,'text','**Mantra tối thượng của Channel System:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ef00531b-f5ef-400c-b576-1aaec8ad8fb0','4b62b628-ef20-4056-82dd-edd3d67ce175',110,'text','*"Đừng bắt bệnh nhân phải đi tìm bạn. Hãy xuất hiện ở mọi nơi họ đi qua, trên mọi nền tảng họ lướt hằng ngày, bằng những định dạng nội dung tử tế và phù hợp nhất với thói quen của họ. Quy hoạch kênh đúng cách chính là cách bạn xây dựng một mạng lưới đánh chặn niềm tin bất khả xâm phạm trên không gian số."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('76ceb676-9965-4670-a880-5454089060cc','26-marketing-os','f3092b4b-84b9-460e-8ae4-9eccae8bf59f',3,'4. MODULE 4: CAMPAIGN SYSTEM - HỆ THỐNG VẬN HÀNH CHIẾN DỊCH ĐỒNG BỘ VÀ KÍCH NỔ DOANH THU ĐIỂM','4-module-4-campaign-system-he-thong-van-hanh-chien-dich-ong-bo-va-kich-no-doanh-',23,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4d59c6e6-e050-40b5-b29c-51af8c059709','26-marketing-os','76ceb676-9965-4670-a880-5454089060cc',5,'4.1 Định nghĩa và tư duy cốt lõi: phá vỡ sự rời rạc, chiến thuật đánh trúng đích','41-inh-nghia-va-tu-duy-cot-loi-pha-vo-su-roi-rac-chien-thuat-anh-trung-ich',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('606a2f30-6df7-4b23-9f70-21f49e41944f','4d59c6e6-e050-40b5-b29c-51af8c059709',111,'text','Một trong những căn bệnh mãn tính của các phòng khám nha khoa tầm trung là vận hành tiếp thị theo kiểu **Chắp vá và Đối phó**. Khi thấy phòng khám vắng khách, doanh thu sụt giảm, chủ nha khoa lập tức hối thúc nhân sự: *"Chạy chương trình giảm giá đi em"* hoặc *"Đăng bài ưu đãi lên Fanpage nhanh lên"*. Các hoạt động này diễn ra một cách ngẫu hứng, thiếu sự đồng bộ giữa khâu sản xuất nội dung, ngân sách quảng cáo, kịch bản chốt sale của tư vấn viên và sự chuẩn bị năng lực lâm sàng của Bác sĩ. Kết quả là tỷ lệ chuyển đổi lẹt đẹt, thương hiệu bị rẻ rúng và nhân sự kiệt quệ vì chạy theo những mệnh lệnh mơ hồ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f4e25201-89db-47b8-b5a3-e645fc1f938a','4d59c6e6-e050-40b5-b29c-51af8c059709',112,'text','Trong hệ điều hành **Dental Empire OS**, chúng tôi thiết lập tư duy: **Marketing không vận hành theo ngày, Marketing vận hành theo Chiến dịch (Campaign-driven Execution).**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d2fc4b2b-0ded-46bd-aff7-9bf31fb4bc28','4d59c6e6-e050-40b5-b29c-51af8c059709',113,'text','Phân hệ **Campaign System** chịu trách nhiệm quy hoạch, đóng gói và kích nổ các hoạt động tiếp thị thành những đợt tấn công đồng bộ, có giới hạn về mặt thời gian, tập trung vào một dịch vụ mũi nhọn và hướng thẳng vào một tệp bệnh nhân mục tiêu duy nhất. Một chiến dịch chuẩn mực là sự phối hợp nhịp nhàng, đồng điệu tuyệt đối giữa 3 bánh răng: *Marketing OS* (Khuếch đại thông điệp) - *Sales OS* (Kịch bản chuyển đổi) — *Clinic OS* (Thực thi phác đồ y khoa), tạo ra sức bật doanh thu mạnh mẽ và đo lường được hiệu quả kinh tế trên từng đồng vốn đầu tư.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('42e58c85-e2ed-4d96-b270-82721fdd0807','26-marketing-os','76ceb676-9965-4670-a880-5454089060cc',5,'4.2 Kiến trúc một sơ đồ chiến dịch chuẩn (Standard Campaign Grid)','42-kien-truc-mot-so-o-chien-dich-chuan-standard-campaign-grid',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bab8d319-502b-4b31-8bc9-19925840a7f5','42e58c85-e2ed-4d96-b270-82721fdd0807',114,'text','Mỗi chiến dịch trước khi được phê duyệt ngân sách kích hoạt trên hệ thống bắt buộc phải được định hình, bóc tách cấu trúc minh bạch qua 10 thành phần cốt lõi dưới đây:',NULL,NULL,NULL,NULL,NULL);
