INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('45983949-2c27-466a-9333-e82551a62558','26-marketing-os','76ceb676-9965-4670-a880-5454089060cc',5,'4.3 BẢN THIẾT KẾ MẪU CHIẾN DỊCH THỰC CHIẾN: CAMPAIGN IMPLANT CONFIDENCE','43-ban-thiet-ke-mau-chien-dich-thuc-chien-campaign-implant-confidence',26,'[]');
