INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f12171c0-a8b3-4283-a685-e307ba3a9dd3','17c8b5f0-683e-4224-b447-7b3716eb9e58',124,'text','Khối Marketing biên soạn Campaign Brief, sản xuất toàn bộ kho nội dung video, bài viết, thiết kế Landing Page. Khối Sales tổ chức học thuộc lòng Script tư vấn mới. Khối Clinic kiểm tra thiết bị cấy ghép, phim chụp sẵn sàng.',NULL,NULL,NULL,NULL,NULL);
