INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f7279e19-3b31-4ce4-a6b5-be9bcfac903a','17c8b5f0-683e-4224-b447-7b3716eb9e58',127,'text','Tung chuỗi nội dung giáo dục tri thức thường thức lên TikTok và YouTube để đánh động điểm đau, làm sạch nhận thức của tệp khách hàng mục tiêu, kích hoạt sự tò mò của bộ tộc người xem.',NULL,NULL,NULL,NULL,NULL);
