INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fad90ba4-1255-48c1-8106-76cf01d6e88c','17c8b5f0-683e-4224-b447-7b3716eb9e58',133,'text','Lễ tân check-in đón tiếp khách show-up chuẩn quy trình 5 sao. Bác sĩ Vinh tư vấn phác đồ trực tiếp tại ghế nha. Đội ngũ Sales kích hoạt luồng bám đuổi (Follow-up) đối với nhóm khách còn lưỡng lự tài chính.',NULL,NULL,NULL,NULL,NULL);
