INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('54a56934-be9f-42a1-9089-fd7946f97263','17c8b5f0-683e-4224-b447-7b3716eb9e58',136,'text','Đóng chiến dịch. Data OS trích xuất toàn bộ chỉ số tài chính, đối soát chi phí quảng cáo với doanh thu thu trước. Chuyển hồ sơ bệnh nhân sang Patient OS để chạy luồng Recall chăm sóc định kỳ trọn năm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0b00b223-8f87-477b-a32e-25f4df81120b','26-marketing-os','76ceb676-9965-4670-a880-5454089060cc',5,'4.5 Bộ chỉ số KPI và mô hình toán học đo lường hiệu quả chiến dịch','45-bo-chi-so-kpi-va-mo-hinh-toan-hoc-o-luong-hieu-qua-chien-dich',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b0a9e32a-826b-4834-9fc7-76e027115f6e','0b00b223-8f87-477b-a32e-25f4df81120b',137,'text','Để đánh giá chiến dịch đang hoạt động sinh lời hay đang đốt tiền vô ích của doanh nghiệp, hệ điều hành thiết lập công thức toán học tối cao kiểm soát **Chỉ số hoàn vốn đầu tư chiến dịch (Campaign ROI)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eaf4d750-f169-4a28-8385-771d000063cf','0b00b223-8f87-477b-a32e-25f4df81120b',138,'text','\\text{Campaign ROI} = \\frac{\\text{Doanh thu thực thu từ Chiến dịch} - \\text{Tổng chi phí Chiến dịch}}{\\text{Tổng chi phí Chiến dịch}}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3f53cae-bcc2-4bfb-9f05-db7c5c322c7d','0b00b223-8f87-477b-a32e-25f4df81120b',139,'text','- *Trong đó:* Tổng chi phí chiến dịch bao gồm Chi phí ngân sách quảng cáo Paid Ads + Chi phí sản xuất ấn phẩm nội dung + Chi phí quà tặng khuyến mãi.- *Mục tiêu tiêu chuẩn:* Chỉ số Campaign ROI phải luôn đạt mốc \\ge 300% (Tức là bỏ 1 đồng chi phí chiến dịch phải thu về ít nhất 3 đồng doanh thu tiền mặt trả trước).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f2c3701c-0b00-43e4-a85e-bf4f8c73c628','26-marketing-os','76ceb676-9965-4670-a880-5454089060cc',5,'4.6 Bộ đầu ra tài liệu tiêu chuẩn đóng gói (Deliverables Bundle)','46-bo-au-ra-tai-lieu-tieu-chuan-ong-goi-deliverables-bundle',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f092fa2f-e1fe-4a44-82ac-4341461821a9','f2c3701c-0b00-43e4-a85e-bf4f8c73c628',140,'text','Để phân hệ Campaign System được nghiệm thu hoàn tất và lưu trữ thành tài sản mã nguồn vận hành lâu dài cho phòng khám, Trưởng phòng tiếp thị bắt buộc phải đóng gói thành công bộ 6 tài liệu kỹ thuật sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6aa5d9de-d5cd-4bc7-a2e8-6371d8b1c7dc','f2c3701c-0b00-43e4-a85e-bf4f8c73c628',141,'text','- **Campaign Brief Template:** Văn bản master quy định rõ ràng mục tiêu, tệp đối tượng, thông điệp, offer đặc quyền và bảng phân bổ ngân sách chi tiết cho chiến dịch.- **Campaign Content Plan Sheet:** File ma trận lập lịch chi tiết ngày giờ phát sóng các bài viết, video, hình ảnh đạn dược phục vụ riêng cho chiến dịch.- **Campaign Landing Flow Chart:** Bản thiết kế sơ đồ dòng chảy trải nghiệm của bệnh nhân từ lúc click vào quảng cáo, đọc Landing Page cho đến khi điền Form nạp data.- **Campaign Dedicated Sales Script:** Bộ tài liệu kịch bản cuộc gọi, kịch bản inbox bóc tách điểm đau được viết riêng cho nhân sự Telesales phục vụ cho chiến dịch đó.- **Campaign KPI Dashboard System:** Bảng cấu hình trường dữ liệu hiển thị thời gian thực các chỉ số CPL, Booking rate, Show-up rate và Doanh thu thu về của chiến dịch.- **Post-campaign Audit Report:** Biểu mẫu báo cáo tổng kết toàn diện, ghi nhận các bài học kinh nghiệm, lý do mất lead để tối ưu hóa năng suất cho các chiến dịch kế tiếp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9acd66a3-c5be-485b-8444-98a610d3e971','f2c3701c-0b00-43e4-a85e-bf4f8c73c628',142,'text','**Mantra tối thượng của Campaign System:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('54a69292-0550-408c-9fcb-5c5a49303dbe','f2c3701c-0b00-43e4-a85e-bf4f8c73c628',143,'text','*"Đừng ném tiền quảng cáo ra ngoài thị trường một cách rời rạc, vô định. Hãy gom toàn bộ nguồn lực con người, tri thức và công nghệ của phòng khám lại thành một mũi khoan chiến dịch sắc bén, đập tan mọi pháo đài hoài nghi và kích nổ dòng doanh thu hữu cơ vượt bậc cho nha khoa."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c1a66759-3c15-4262-ba71-071566b7a2ce','26-marketing-os','f3092b4b-84b9-460e-8ae4-9eccae8bf59f',3,'MODULE 5: TRUST ASSET SYSTEM - HỆ THỐNG QUẢN TRỊ TÀI SẢN NIỀM TIN VÀ PHÁO ĐÀI BẰNG CHỨNG THỰC CHỨNG','module-5-trust-asset-system-he-thong-quan-tri-tai-san-niem-tin-va-phao-ai-bang-c',30,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1930b8d7-46c3-4f06-9291-bc7f4b7414c4','26-marketing-os','c1a66759-3c15-4262-ba71-071566b7a2ce',5,'5.1. Định nghĩa và tư duy cốt lõi: nền kinh tế bằng chứng, tích lũy tài sản lòng tin','51-inh-nghia-va-tu-duy-cot-loi-nen-kinh-te-bang-chung-tich-luy-tai-san-long-tin',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b240b564-9dea-492c-9300-5ae303051903','1930b8d7-46c3-4f06-9291-bc7f4b7414c4',144,'text','Một trong những sai lầm ngây thơ nhất của các nhà quản lý nha khoa truyền thống là tin rằng một bài viết quảng cáo hay hoặc một ngân sách chạy Ads lớn có thể thuyết phục bệnh nhân xuống tiền cho một ca Implant toàn hàm hay một phác đồ chỉnh nha phức tạp. Trong y khoa can thiệp sâu, **Niềm tin không bao giờ được sản sinh từ những lời hứa hẹn một chiều của bộ phận tiếp thị.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c3ebab8-9a82-41a3-b341-1904b0462561','1930b8d7-46c3-4f06-9291-bc7f4b7414c4',145,'text','Bản chất tâm lý của bệnh nhân khi đối mặt với nha khoa là trạng thái hoài nghi cực độ, được chi phối bởi hai nỗi sợ lớn hằng ngày: Nỗi sợ bị lừa dối về mặt chi phí/chất lượng vật liệu và nỗi sợ đau đớn, biến chứng sinh học trên chính cơ thể mình. Để phá vỡ pháo đài phòng thủ này, phòng khám không thể dùng lời nói suông. Bạn bắt buộc phải vận hành một **Nền kinh tế bằng chứng (Evidence-based Marketing)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7ec18f72-eaf9-46e9-9fb7-21b08e3195e0','1930b8d7-46c3-4f06-9291-bc7f4b7414c4',146,'text','Hệ điều hành **Dental Empire OS** quy định: **Niềm tin là một loại tài sản doanh nghiệp có thể quy hoạch, tích lũy, số hóa và đo lường được bằng toán học quản trị.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('39a165ee-a6df-4310-b23d-fe975d4f4f95','1930b8d7-46c3-4f06-9291-bc7f4b7414c4',147,'text','Phân hệ **Trust Asset System** chịu trách nhiệm thu thập, phân loại, đóng gói và phân phối toàn bộ hệ thống bằng chứng thực chứng lâm sàng lẫn cảm xúc. Mỗi bài đánh giá 5 sao, mỗi hình ảnh Before/After, mỗi video phân tích chuyên môn của Bác sĩ Nguyễn Phước Vinh không phải là nội dung đăng lên cho vui, mà là một **Mỏ neo tài sản niềm tin (Trust Asset)**. Khi hệ thống của bạn tích lũy khối lượng tài sản này đủ lớn hằng năm, bạn sẽ tự động bẻ gãy mọi sự phản kháng về giá của khách hàng từ trước khi họ bước chân vào phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('16e060a9-4a72-4df7-b54d-d1a0c2a49787','26-marketing-os','c1a66759-3c15-4262-ba71-071566b7a2ce',5,'5.2 Ma trận 10 loại tài sản niềm tin chiến lược tại phòng khám RHM','52-ma-tran-10-loai-tai-san-niem-tin-chien-luoc-tai-phong-kham-rhm',32,'[]');
