INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ed266068-9e9a-4d3d-b7d3-f4fd404c985b','55e474bd-f0b2-40a3-aa1a-589d7eb6e8f7',157,'text','Tại buổi hẹn tái khám kiểm tra cuối cùng, khi bệnh nhân đạt trạng thái hạnh phúc đỉnh cao với nụ cười mới, bộ phận CSKH trực sàn kích hoạt Script hướng dẫn khách quét mã QR để lại đánh giá trên Google Maps và quay video ngắn phỏng vấn nhanh cảm nhận.',NULL,NULL,NULL,NULL,NULL);
