INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1adc1a76-8b5c-491d-aa5d-182ba208b653','55e474bd-f0b2-40a3-aa1a-589d7eb6e8f7',160,'text','Khối Marketing tiếp nhận nguyên liệu thô, tiến hành hậu kỳ chỉnh sửa (Xóa mờ thông tin nhạy cảm của khách để bảo mật y tế), gắn mã số hóa theo chuẩn hệ thống (Ví dụ: `TA-CASE-IMPLANT-042`) và đẩy vào thư viện lưu trữ trung tâm.',NULL,NULL,NULL,NULL,NULL);
