INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('468d1086-e363-45d8-81d1-d913b044ca7f','55e474bd-f0b2-40a3-aa1a-589d7eb6e8f7',163,'text','Tự động đồng bộ tài sản lên Website, ghim bài viết lên Fanpage để nuôi dưỡng tệp lead ấm, đồng thời cấu hình Schema dữ liệu cấu trúc để đánh chặn các mô hình tìm kiếm thông minh bằng trí tuệ nhân tạo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ac9183eb-5b2a-4fe3-93a4-efcbeebec8d9','26-marketing-os','c1a66759-3c15-4262-ba71-071566b7a2ce',5,'5.5 Chỉ số định lượng sức mạnh niềm tin (Mathematical Trust Index)','55-chi-so-inh-luong-suc-manh-niem-tin-mathematical-trust-index',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dcaf8c59-d78f-4a90-b54f-f1708a4b92cb','ac9183eb-5b2a-4fe3-93a4-efcbeebec8d9',164,'text','Để triệt tiêu hoàn toàn cách đánh giá cảm tính, hệ điều hành *Data OS* thiết lập công thức toán học cấu trúc tính toán **Chỉ số Tích lũy Niềm tin Hệ thống (Trust Accumulation Index - TAI)** hằng tháng nhằm dự báo chính xác tỷ lệ ma sát chuyển đổi đầu phễu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('93938a13-2e10-4e5a-b007-5f1dc475f59a','ac9183eb-5b2a-4fe3-93a4-efcbeebec8d9',165,'text','TAI = \\frac{\\sum_{i=1}^{n} (C_i \\times w_c) + \\sum_{j=1}^{m} (R_j \\times w_r)}{CAC}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1107e265-6ccd-4dbc-9f79-632fca7fa72f','ac9183eb-5b2a-4fe3-93a4-efcbeebec8d9',166,'text','*Trong đó:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('09c187da-27bb-49f7-a101-4a454135aec3','ac9183eb-5b2a-4fe3-93a4-efcbeebec8d9',167,'text','- C_i: Số lượng bộ tài sản Case Study lâm sàng Trước - Sau được cập nhật mới chuẩn SLA.- R_j: Số lượng bài đánh giá 5 sao viết dài, có hình ảnh thực tế được kích hoạt trên các nền tảng kiểm chứng độc lập.- w_c, w_r: Trọng số chuyển đổi kỹ thuật quy định cho từng dịch vụ (Ví dụ: Một ca Implant toàn hàm phức tạp có trọng số w_c = 5.0, một ca trám răng thông thường có trọng số w_c = 0.5).- CAC: Chi phí sắm một khách hàng mới trong tháng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b0bd684-575f-491d-85f3-be0c47cbdfbb','ac9183eb-5b2a-4fe3-93a4-efcbeebec8d9',168,'text','Chỉ số TAI đạt tỷ lệ đồng thuận cao khi tăng trưởng lũy tiến qua các quý. Nó chứng minh phòng khám đang ngày càng tích lũy được nhiều bằng chứng thép, giúp giảm tải tối đa áp lực chi phí quảng cáo Paid Ads đầu phễu của doanh nghiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('205b11ce-dcf1-4336-bc5e-8ae523a9040f','26-marketing-os','c1a66759-3c15-4262-ba71-071566b7a2ce',5,'5.6 Bộ đầu ra tài liệu tiêu chuẩn đóng gói (Deliverables Bundle)','56-bo-au-ra-tai-lieu-tieu-chuan-ong-goi-deliverables-bundle',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c833eb92-3495-47f6-8878-72e81df2efff','205b11ce-dcf1-4336-bc5e-8ae523a9040f',169,'text','Để cấu phần Trust Asset System được nghiệm thu hoàn tất và lưu trữ thành tài sản mã nguồn vận hành lâu dài cho phòng khám **Thích Làm Răng**, ban điều hành bắt buộc phải hoàn thiện bộ 7 tài sản quản trị số hóa sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ecd9aff6-33aa-470f-b2cc-8c3a6f6de0cb','205b11ce-dcf1-4336-bc5e-8ae523a9040f',170,'text','- **Central Trust Asset Library:** File Master quản trị kho lưu trữ tổng hợp, phân tầng phân quyền cho phép Telesales và Chuyên viên tư vấn truy cập trích xuất đạn dược chốt sale cấp tốc.- **Standardized Case Library:** Thư viện hình ảnh lâm sàng Trước - Sau được bóc tách khoa học theo từng dòng bệnh lý, dịch vụ mũi nhọn và loại vật liệu sử dụng.- **Patient Review & Video Testimonial Bank:** Kho lưu trữ ảnh chụp màn hình feedback tin nhắn Zalo, file video gốc phỏng vấn bệnh nhân VIP phục hình thành công.- **Doctor Profile Performance Kit:** Bộ hồ sơ năng lực điện tử và bản in cứng của Bác sĩ sáng lập Nguyễn Phước Vinh, thiết kế chuẩn nhận diện thương hiệu đẳng cấp thượng lưu.- **Google Business Profile Optimization Checklist:** Quy trình 12 bước tối ưu kỹ thuật SEO/GEO địa phương hằng tuần để bản đồ phòng khám luôn lọt top hiển thị tìm kiếm khẩn cấp của cư dân.- **Website Trust Section Specifications:** Bản đặc tả kỹ thuật thiết kế vùng không gian mỏ neo niềm tin trên trang chủ (Vùng hiển thị chứng chỉ, vùng slide ảnh Before/After kéo trượt trực quan).- **AI Visibility Asset List (Cấu trúc dữ liệu đánh chặn LLM):** Tài sản tối mật của năm 2026. Danh mục cấu trúc Schema dữ liệu, bài phân tích y khoa tầng sâu được tối ưu kỹ thuật cấu trúc mã lệnh để các mô hình trí tuệ nhân tạo lớn (Gemini, ChatGPT, SearchGPT) quét trích xuất và ưu tiên đề xuất thương hiệu của bạn khi người dùng gõ lệnh hỏi AI: *"Nha khoa nào cấy ghép Implant và Chỉnh nha tử tế, uy tín nhất tại Hà Nội?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2ae434ed-6a38-48c5-be7b-4134fd67e994','205b11ce-dcf1-4336-bc5e-8ae523a9040f',171,'text','**Mantra tối thượng của Trust Asset System:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('740759bf-b198-46e9-8296-29d1d7e42bb3','205b11ce-dcf1-4336-bc5e-8ae523a9040f',172,'text','*"Một bài quảng cáo hay chỉ có thể mua được lượt click của khách hàng, nhưng một pháo đài bằng chứng thực chứng được tích lũy kỷ luật hằng ngày mới là thứ duy nhất mua được lòng tin tuyệt đối và lòng biết ơn trọn đời của bệnh nhân."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ec60fcb9-2c5d-4be6-b7dd-654b7ed4a612','26-marketing-os','f3092b4b-84b9-460e-8ae4-9eccae8bf59f',3,'MODULE 6: LEAD MANAGEMENT - HỆ THỐNG QUẢN TRỊ DÒNG DỮ LIỆU VÀ ĐỒNG BỘ ĐƯỜNG ỐNG TIẾP THỊ - CHUYỂN ĐỔI','module-6-lead-management-he-thong-quan-tri-dong-du-lieu-va-ong-bo-uong-ong-tiep-',37,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3c3c0ef4-9db4-4f56-9cd3-4f6e6e3a8560','26-marketing-os','ec60fcb9-2c5d-4be6-b7dd-654b7ed4a612',5,'6.1 Định nghĩa và tư duy cốt lõi: đập tan tư duy silo, số hóa đường ống dữ liệu đồng bộ','61-inh-nghia-va-tu-duy-cot-loi-ap-tan-tu-duy-silo-so-hoa-uong-ong-du-lieu-ong-bo',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('89683dd3-3dee-4ba6-8f0b-8b9d5533b1eb','3c3c0ef4-9db4-4f56-9cd3-4f6e6e3a8560',173,'text','Một trong những xung đột kinh điển và gây lãng phí nguồn lực lớn nhất tại các phòng khám nha khoa hiện nay là cuộc chiến ngầm giữa bộ phận Marketing và bộ phận Sales. Marketing luôn than phiền: *"Chúng tôi mang về rất nhiều lead nhưng Sales không chịu gọi điện hoặc tư vấn quá dở khiến ca bị rớt"*. Ngược lại, Sales phản pháo: *"Lead từ quảng cáo đổ về toàn dữ liệu rác, số điện thoại ảo, sai phân khúc thu nhập thì làm sao chốt được phác đồ Implant hay Chỉnh nha!"*. Xung đột này xảy ra do phòng khám thiếu một hệ thống **Quản trị Lead tập trung (Lead Management System)** để đóng vai trò làm trọng tài và phân định minh bạch bằng dữ liệu thời gian thực.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d7085a3a-96b3-4bc5-8fbe-7ed07bf64805','3c3c0ef4-9db4-4f56-9cd3-4f6e6e3a8560',174,'text','Trong hệ điều hành **Dental Empire OS**, chúng tôi thiết lập một nguyên tắc quản trị bất di dịch: **Chiến dịch tiếp thị không kết thúc ở thời điểm thu về một Lead thô. Tiếp thị chỉ thực sự hoàn tất khi dòng dữ liệu đó được chuyển hóa thành Bệnh nhân điều trị và sản sinh ra dòng tiền mặt thực thu.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6d8e250e-50e1-4381-8397-6754efc10c5c','3c3c0ef4-9db4-4f56-9cd3-4f6e6e3a8560',175,'text','Phân hệ **Lead Management** đóng vai trò là một "nhà máy xử lý và định tuyến dữ liệu tự động". Nó giúp xóa bỏ hoàn toàn lỗ hổng thất thoát thông tin, bắt buộc khối tiếp thị và khối tư vấn phải nhìn vào cùng một trường sự thật hiển thị trên CRM. Phân hệ này theo dõi sát sao từng mốc dịch chuyển sinh học của một hồ sơ từ lúc phát sinh tin nhắn đầu tiên cho đến khi dòng tiền mặt được hạch toán, từ đó thực hiện khớp nguồn doanh thu (*Revenue Attribution*) chính xác cho từng chiến dịch nội dung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e8b58037-4741-4a18-8b8d-23c6eb678d76','26-marketing-os','ec60fcb9-2c5d-4be6-b7dd-654b7ed4a612',5,'6.2 Luồng vận hành dòng chảy Lead Flow chuẩn hóa','62-luong-van-hanh-dong-chay-lead-flow-chuan-hoa',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0aaa6fd3-8632-432e-882d-d287b8698b86','e8b58037-4741-4a18-8b8d-23c6eb678d76',176,'text','Mỗi một hồ sơ dữ liệu khi đổ về từ Media Network bắt buộc phải chạy qua đúng chu trình trục dọc 9 bước nghiêm ngặt dưới đây để đảm bảo độ mượt mà và tính bảo mật y tế:',NULL,NULL,NULL,NULL,NULL);
