INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e48e1929-b7c7-4ea0-84cf-72682ae33e46','26-marketing-os','ec60fcb9-2c5d-4be6-b7dd-654b7ed4a612',5,'6.3 Ma trận phân tầng 12 trạng thái lead tiêu chuẩn (Lead Status Matrix)','63-ma-tran-phan-tang-12-trang-thai-lead-tieu-chuan-lead-status-matrix',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4564b95a-8291-4daf-a376-8ac2308877d3','e48e1929-b7c7-4ea0-84cf-72682ae33e46',178,'text','Để toàn bộ đội ngũ nhân sự sàn vận hành và nhân sự online sử dụng chung một ngôn ngữ kỹ thuật, hệ thống CRM cấu hình cứng 12 trạng thái tiến độ của Lead như sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bdae8d8a-6e27-4895-91a6-93d6c40ea73c','e48e1929-b7c7-4ea0-84cf-72682ae33e46',179,'image',NULL,'book/26-marketing-os/f61cdd7d-5841-4056-a6af-3dcf39e6d41c-img14.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c1a56b2e-a822-437e-bfd9-9c3a3031b78a','26-marketing-os','ec60fcb9-2c5d-4be6-b7dd-654b7ed4a612',5,'6.4 Bản đặc tả 10 trường dữ liệu bắt buộc cho mỗi hồ sơ lead','64-ban-ac-ta-10-truong-du-lieu-bat-buoc-cho-moi-ho-so-lead',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92917eb5-1631-4b19-8782-2cd82d98a5df','c1a56b2e-a822-437e-bfd9-9c3a3031b78a',180,'text','Tuyệt đối không lưu trữ thông tin bệnh nhân một cách manh mún, thiếu cấu trúc. Mỗi một trường dữ liệu (Data Field) tạo lập trên hệ thống bắt buộc phải điền đầy đủ các thông tin kiểm soát sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1259dfde-0c4e-4fcd-97e8-92d0db3116f8','c1a56b2e-a822-437e-bfd9-9c3a3031b78a',181,'image',NULL,'book/26-marketing-os/60960f9c-f9a5-447b-bf64-02a741f9ddea-img15.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5c82f4a6-8ae1-421a-a1c3-0ea053ea019e','26-marketing-os','ec60fcb9-2c5d-4be6-b7dd-654b7ed4a612',5,'6.5 Quy trình chuyển giao sàn chuẩn SLA (Sales handoff process) &amp; phương trình khớp nguồn doanh thu','65-quy-trinh-chuyen-giao-san-chuan-sla-sales-handoff-process-amp-phuong-trinh-kh',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0b8bf171-e62b-4d06-8e84-ac1d4927f547','5c82f4a6-8ae1-421a-a1c3-0ea053ea019e',182,'text','Để đảm bảo không có một lead nào bị rơi rụng do sự chậm trễ của con người, hệ điều hành thiết lập quy trình chuyển giao dữ liệu (Handoff SOP) áp dụng **Kỷ luật thời gian thép (SLA Throttling)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9fab1887-7d29-4853-9988-169780cc8242','5c82f4a6-8ae1-421a-a1c3-0ea053ea019e',183,'text','- **SLA 1 (Tốc độ tiếp cận cuộc gọi đầu):** Kể từ khi Lead chuyển sang trạng thái `NEW` trên hệ thống, Sales Owner được chỉ định bắt buộc phải thực hiện cuộc gọi hoặc nhắn tin phá băng đầu tiên trong thời gian **ít hơn hoặc bằng 3 phút**.- **SLA 2 (Thời hạn xử lý trạng thái):** Một hồ sơ không được phép nằm ở trạng thái `NEW` hoặc `Contacted` quá 24 giờ. Nhân sự phải chủ động phân loại để dịch chuyển sang nhóm `Qualified`, `Unqualified` hoặc `Lost`.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c13bb64-f0b9-4f72-b0ef-79a63a842586','5c82f4a6-8ae1-421a-a1c3-0ea053ea019e',184,'text','Để đo lường độ bén về mặt kinh tế của toàn bộ đường ống này, hệ điều hành *Data OS* áp dụng công thức toán học tính toán chỉ số **Hiệu suất Chuyển đổi Đường ống (Pipeline Conversion Efficiency - PCE)** hằng tháng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bbcceea2-7b6c-44fe-8053-d4493598ef4e','5c82f4a6-8ae1-421a-a1c3-0ea053ea019e',185,'text','PCE = \\left( \\frac{\\text{Số lượng Lead trạng thái STA}}{\\text{Tổng số lượng Lead trạng thái QUA}} \\right) \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('65f8bf06-8aee-4268-a488-deac96ae9979','5c82f4a6-8ae1-421a-a1c3-0ea053ea019e',186,'text','Và chỉ số hạch toán **Khớp nguồn doanh thu tiếp thị (Marketing Revenue Attribution Index - RAI)** để đo lường chính xác hiệu quả sinh lời của từng chiến dịch nội dung:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('39139399-7dd0-4413-8a1c-4f40e7711d67','5c82f4a6-8ae1-421a-a1c3-0ea053ea019e',187,'text','RAI_{\\text{Campaign}} = \\frac{\\sum \\text{Net Revenue từ nhóm Lead có mã Campaign ID tương ứng}}{\\text{Tổng ngân sách chi phí quảng cáo của Campaign đó}}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aab70847-ac13-412f-a4dc-cd96a6cf0ac1','5c82f4a6-8ae1-421a-a1c3-0ea053ea019e',188,'text','Chỉ số RAI \\ge 3.0 là ngưỡng tiêu chuẩn đạt độ chín vận hành, chứng minh chiến dịch tiếp thị của thương hiệu **Thích Làm Răng** đang đi đúng hướng và sản sinh ra dòng tiền mặt hữu cơ khỏe mạnh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7fed58eb-00d1-4ffc-a63e-5794f0fe5e9a','5c82f4a6-8ae1-421a-a1c3-0ea053ea019e',189,'image',NULL,'book/26-marketing-os/54c01700-50ac-4401-816f-c5b4fc809300-img16.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('81677a6c-475c-4242-9d9c-ba34dea72c33','26-marketing-os','ec60fcb9-2c5d-4be6-b7dd-654b7ed4a612',5,'6.6 Bộ đầu ra tài liệu tiêu chuẩn đóng gói (Deliverables Bundle)','66-bo-au-ra-tai-lieu-tieu-chuan-ong-goi-deliverables-bundle',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ec1dc424-cd43-42bf-a24a-539558623f1b','81677a6c-475c-4242-9d9c-ba34dea72c33',190,'text','Để phân hệ Lead Management được nghiệm thu hoàn tất và đóng dấu lưu trữ thành mã nguồn tài sản của nha khoa, ban điều hành bắt buộc phải hoàn thiện bộ 6 tài liệu kỹ thuật số hóa sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('61676201-13b9-418e-aafa-ee197825ece8','81677a6c-475c-4242-9d9c-ba34dea72c33',191,'text','- **Lead Intake Form Specifications:** Bản đặc tả cấu trúc thiết kế Form thu nạp dữ liệu đa kênh, đồng bộ API trực tiếp từ không gian mạng về phần mềm CRM trung tâm phòng khám.- **CRM Lead Status Configuration Blueprint:** Bản hướng dẫn lập trình cấu hình 12 trạng thái dữ liệu, thiết lập cơ chế tự động phân phối Lead xoay vòng (Round-Robin) cho nhân sự Sales.- **Lead Source Taxonomy Document:** Cuốn từ điển phân loại và quy định chuẩn hóa cách đặt tên mã nguồn Lead, mã chiến dịch truyền thông nhằm triệt tiêu lỗi sai lệch dữ liệu đầu vào.- **Online-to-Offline Sales Handoff SOP:** Văn bản quy trình bàn giao hồ sơ y khoa, thông tin phim chụp sơ bộ và đặc điểm tâm lý khách hàng từ bộ phận tư vấn online sang cho đội ngũ Lễ tân và Bác sĩ trực sàn điều trị.- **Weekly Lead Quality Auditing Report:** Biểu mẫu báo cáo kiểm toán chất lượng Lead hằng tuần, bóc tách chi tiết tỷ lệ Qualified Data của từng kênh truyền thông xã hội để kịp thời căn chỉnh ngân sách Ads.- **Revenue Attribution Tracking Dashboard:** Hệ thống bảng hiển thị thời gian thực theo dõi chính xác dòng tiền mặt trả trước thu về, đối soát khớp nguồn trực tiếp với từng kịch bản video ngắn và bài viết trên Media Network.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('647cd5ff-15fc-437e-83cd-790fbbfcfa29','81677a6c-475c-4242-9d9c-ba34dea72c33',192,'text','**Mantra tối thượng của Lead Management:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9d16b5c-0905-43f6-92fa-acff49a1fffd','81677a6c-475c-4242-9d9c-ba34dea72c33',193,'text','*"Mỗi một lead dữ liệu đổ về hệ thống là một nụ cười đang chịu tổn thương và gửi gắm niềm tin vào phòng khám. Đừng bao giờ để sự chậm trễ hay thói quen làm việc cẩu thả của con người làm đứt gãy đường ống dữ liệu, tự cắt đứt cơ hội được chăm sóc tử tế của bệnh nhân."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9c63eed9-ed49-41cf-9e1c-429a29d44aef','26-marketing-os','f3092b4b-84b9-460e-8ae4-9eccae8bf59f',3,'MODULE 7: DATA &amp; REPORTING - HỆ THỐNG PHÂN TÍCH DỮ LIỆU VÀ KHOANG LÁI QUẢN TRỊ TIẾP THỊ CHỦ ĐỘNG','module-7-data-amp-reporting-he-thong-phan-tich-du-lieu-va-khoang-lai-quan-tri-ti',44,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1df8dd6a-b218-4acc-829f-d1a6409008fc','26-marketing-os','9c63eed9-ed49-41cf-9e1c-429a29d44aef',5,'7.1 Định nghĩa và tư duy cốt lõi: triệt tiêu cảm tính, số hóa khoang lái điều hành','71-inh-nghia-va-tu-duy-cot-loi-triet-tieu-cam-tinh-so-hoa-khoang-lai-ieu-hanh',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ba04c2c-8ece-45cb-95e0-c42652a2af8f','1df8dd6a-b218-4acc-829f-d1a6409008fc',194,'text','Căn bệnh chí mạng cuối cùng làm sụp đổ các chiến dịch truyền thông nha khoa là **Quản trị bằng cảm giác**. Khi được hỏi về hiệu quả tiếp thị, đội ngũ nhân sự thường báo cáo theo kiểu: *"Tháng này em thấy tương tác tốt"* hoặc *"Hình như dạo này khách hỏi về Implant đông hơn"*. Việc dùng những tính từ định tính mơ hồ này để điều hành bộ máy khiến phòng khám liên tục đưa ra các quyết định sai lầm: Đốt tiền vào những kênh không sinh lời, cắt bỏ những nội dung đang âm thầm tạo lòng tin, hoặc scale up (mở rộng) các chiến dịch đang chịu lỗ ngầm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ca37954b-91d2-48ba-beb6-5adf4f53e756','1df8dd6a-b218-4acc-829f-d1a6409008fc',195,'text','In hệ điều hành **Dental Empire OS**, chúng tôi thiết lập một nguyên tắc tối cao: **Dữ liệu không có cảm xúc, dữ liệu chỉ nói lên sự thật. Những gì không đo lường được thì không thể quản trị được.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b2f14ff3-9e89-4ac9-921e-aa018463e9e8','1df8dd6a-b218-4acc-829f-d1a6409008fc',196,'text','Phân hệ **Data & Reporting** đóng vai trò là hệ thần kinh trung ương của *Marketing OS*. Nó chịu trách nhiệm thu thập, xử lý và trực quan hóa toàn bộ các biến số hành vi và tài chính trên không gian mạng hằng ngày. Phân hệ này ra đời để giải phóng **Bác sĩ Nguyễn Phước Vinh** cùng ban điều hành khỏi sự nhiễu loạn thông tin, cung cấp một "khoang lái máy bay" hiển thị thời gian thực để đưa ra các quyết định cắt giảm hay bơm ngân sách dựa trên hiệu quả kinh tế thực chứng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b507c857-c2d8-4cd3-a109-0dea27aed5a3','26-marketing-os','9c63eed9-ed49-41cf-9e1c-429a29d44aef',5,'7.2 Sáu câu hỏi sinh tử ban giám đốc cần lời giải đáp','72-sau-cau-hoi-sinh-tu-ban-giam-oc-can-loi-giai-ap',46,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1d7d02a7-e2d2-4f84-8f3c-9b29099d4957','b507c857-c2d8-4cd3-a109-0dea27aed5a3',197,'text','Hằng ngày, hệ thống dữ liệu phải tự động phân tích và đưa ra câu trả lời định lượng cho 6 bài toán cân não của nhà quản trị:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cd4ce115-3b8a-41f8-8714-62a9f0e9ebf3','b507c857-c2d8-4cd3-a109-0dea27aed5a3',198,'text','- **Định tuyến kênh tối ưu (Channel Efficiency):** Kênh phân phối nào (TikTok, Facebook, Website, Google Maps) đang mang lại hiệu quả kinh tế cao nhất trên mỗi đồng chi phí?- **Xác định nội dung mồi (Content Winners):** Định dạng nội dung hoặc kịch bản video ngắn nào của kênh đang sở hữu năng lực giáo dục thường thức và tạo lead nóng tốt nhất?- **Đo lường sức khỏe chiến dịch (Campaign Performance):** Chiến dịch tiếp thị nào đang vận hành mượt mà, kích nổ lượng cuộc hẹn (Booking) lớn vượt trội?- **Định vị tệp khách hàng giá trị cao (High-LTV Identification):** Nguồn lead đến từ đâu đang sản sinh ra những bệnh nhân đồng ý phác đồ can thiệp sâu (Implant, Chỉnh nha) có giá trị đơn hàng lớn nhất?- **Kiểm soát biến động chi phí (Cost Fluctuation):** Chỉ số chi phí trên mỗi lead (CPL) và chi phí sắm khách (CAC) đang tăng hay giảm so với chu kỳ tháng trước?- **Quyết định ngân sách chiến lược (Scaling Decisions):** Đâu là thời điểm vàng để lập tức nhân bản cấu trúc chiến dịch lên quy mô lớn hoặc bấm nút khai tử một luồng quảng cáo lỗi?',NULL,NULL,NULL,NULL,NULL);
