INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('47782675-9e18-412a-917a-d375eb7f8d2d','26-marketing-os','9c63eed9-ed49-41cf-9e1c-429a29d44aef',5,'7.4 Lộ trình đối soát và tần suất báo cáo (Reporting Lifecycle)','74-lo-trinh-oi-soat-va-tan-suat-bao-cao-reporting-lifecycle',48,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('24683993-e71e-47db-ad09-ca07904eb054','47782675-9e18-412a-917a-d375eb7f8d2d',201,'text','Nhân sự không làm báo cáo để đối phó cuối tháng. Luồng trích xuất dữ liệu được thiết lập chạy ngầm và kiểm toán theo chu kỳ 3 tầng nghiêm ngặt nhằm đảm bảo tính linh hoạt tối đa cho bộ máy:',NULL,NULL,NULL,NULL,NULL);
