INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48bd400e-64ec-4b61-adbc-af69e2cf4720','47782675-9e18-412a-917a-d375eb7f8d2d',203,'text','*Tần suất hằng ngày (Daily Check).*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b02d4e39-e2a7-405e-85f1-052b1764bef1','47782675-9e18-412a-917a-d375eb7f8d2d',204,'text','Trích xuất các chỉ số: Số lượng Lead mới nạp, Ngân sách tiêu hao thực tế, chỉ số CPL hằng ngày. Mục tiêu: Phát hiện sớm các lỗi kỹ thuật (Lỗi chết link form, lỗi quảng cáo bị từ chối, lead rác tràn vào hệ thống).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b03e6f9d-0d6e-4a9d-bb5a-f61f70341a41','47782675-9e18-412a-917a-d375eb7f8d2d',205,'text','**2.2. Đánh giá chất lượng và tối ưu hóa dây chuyền:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('da732920-5c47-49f2-87f5-7efc150f726e','47782675-9e18-412a-917a-d375eb7f8d2d',206,'text','*Tần suất hằng tuần (Weekly Audit).*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6e0db816-6255-4a01-aae6-a0d2978d6224','47782675-9e18-412a-917a-d375eb7f8d2d',207,'text','Đối soát các chỉ số: Tỷ lệ chuyển đổi kênh (Channel performance), các nội dung video/bài viết đạt tương tác đỉnh cao (Content winners), và chất lượng lịch hẹn của Sales (Booking quality). Mục tiêu: Điều chỉnh kịch bản và phân bổ lại lịch biên tập.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ab92616-57b8-45d6-9895-7ac4f4ea2c58','47782675-9e18-412a-917a-d375eb7f8d2d',208,'text','**3.3. Quyết định chiến lược vĩ mô và hạch toán ROI:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4c94d2e0-da3f-4882-8b38-f680265bdaf5','47782675-9e18-412a-917a-d375eb7f8d2d',209,'text','*Tần suất hằng tháng (Monthly Review).*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('78dcb874-84e2-4cb2-95c5-656c00f7beca','47782675-9e18-412a-917a-d375eb7f8d2d',210,'text','Nghiệm thu toàn diện các chỉ số vĩ mô: Chỉ số CAC tổng, Doanh thu khớp nguồn trên từng dịch vụ mũi nhọn, và chỉ số hoàn vốn tiếp thị (Marketing ROI). Mục tiêu: Đưa ra quyết định chiến lược về việc nhân bản hệ thống hoặc dịch chuyển dòng tiền đầu tư quý tới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('55dd3819-47e0-40b8-a4ea-fa751ef9af45','26-marketing-os','9c63eed9-ed49-41cf-9e1c-429a29d44aef',5,'7.5 Mỏ neo toán học: phương trình hiệu suất tiếp thị tối cao','75-mo-neo-toan-hoc-phuong-trinh-hieu-suat-tiep-thi-toi-cao',49,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('851cc433-01c2-41a9-bd2d-0e8d7279849f','55dd3819-47e0-40b8-a4ea-fa751ef9af45',211,'text','Để triệt tiêu hoàn toàn các báo cáo ảo về lượt view hay lượt like, hệ điều hành *Data OS* cài đặt công thức toán học tối cao đo lường **Tỷ lệ Hiệu suất Tiếp thị Tổng thể (Marketing Efficiency Ratio - MER)** hằng tháng để làm thước đo năng lực sinh lời của phòng khám:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd2da976-ccf3-4a1a-aa32-e0cbcd7f5006','55dd3819-47e0-40b8-a4ea-fa751ef9af45',212,'text','MER = \\frac{\\text{Tổng doanh thu ròng thực thu sản sinh từ Tiếp thị}}{\\text{Tổng ngân sách chi phí quảng cáo Paid Ads}}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('544f3546-0651-4293-961c-a95cca71d306','55dd3819-47e0-40b8-a4ea-fa751ef9af45',213,'text','Chỉ số MER chính là mỏ neo định lượng tối hậu cho ban giám đốc. Nếu MER < 3.0, hệ thống tiếp thị đang chạm ngưỡng báo động đỏ về mặt hiệu quả kinh tế. Khi MER \\ge 5.0, phòng khám đang sở hữu một cỗ máy in tiền hữu cơ khỏe mạnh, sẵn sàng cho các quyết định bơm thêm ngân sách để chiếm lĩnh thị trường địa phương.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('152d1925-e22d-47ea-b0b9-29644b185ce2','26-marketing-os','9c63eed9-ed49-41cf-9e1c-429a29d44aef',5,'7.6 Bộ đầu ra tài liệu tiêu chuẩn đóng gói (Deliverables Bundle)','76-bo-au-ra-tai-lieu-tieu-chuan-ong-goi-deliverables-bundle',50,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4e7dd20a-ae9b-43d5-80e5-17951703717d','152d1925-e22d-47ea-b0b9-29644b185ce2',214,'text','Để phân hệ Data & Reporting được nghiệm thu hoàn tất và lưu trữ thành tài sản mã nguồn vận hành lâu dài cho phòng khám, đội ngũ kỹ thuật bắt buộc phải đóng gói thành công bộ 6 tài sản quản trị số hóa sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a272c54-9108-49f7-8905-9ef8aaa7aeb9','152d1925-e22d-47ea-b0b9-29644b185ce2',215,'text','- **Master Marketing Dashboard Spec:** Bản đặc tả kỹ thuật và giao diện bảng điều khiển trung tâm hiển thị thời gian thực, liên kết API tự động từ CRM và các nền tảng mạng xã hội.- **Campaign Performance Report Template:** Biểu mẫu cấu trúc báo cáo bóc tách chi tiết hiệu quả kinh tế của từng chiến dịch thương mại mũi nhọn hằng tuần.- **Content Performance Audit Sheet:** File theo dõi và phân loại chỉ số tương tác, số lượng lead sản sinh trực tiếp từ kho kịch bản nội dung của kênh.- **Omnichannel Channel ROI Framework:** Bản biểu mẫu đối soát doanh thu ròng khớp nguồn theo từng kênh phân phối, phục vụ cho tác vụ tối ưu hóa chi phí quảng cáo hằng tháng.- **CAC Lifecycle Calculator Tracker:** Công cụ tự động tính toán chính xác chỉ số chi phí sắm một khách hàng mới theo từng dòng dịch vụ can thiệp sâu (Implant đơn lẻ, Implant toàn hàm, Chỉnh nha mắc cài, Invisalign).- **Weekly Insight & Action Snapshot:** Mẫu văn bản rút gọn trích xuất các điểm sáng dữ liệu hằng tuần kèm theo bản đề xuất hành động thực địa (Action Plan) gửi trực tiếp lên Founder Bác sĩ Vinh trước mỗi buổi họp giao ban sàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3562e025-36a6-4da2-97bf-99c912926ee3','152d1925-e22d-47ea-b0b9-29644b185ce2',216,'text','**Mantra tối thượng của Data & Reporting:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('96d4f994-2e1e-452a-afe2-f6a8a4185023','152d1925-e22d-47ea-b0b9-29644b185ce2',217,'text','*"Đừng bao giờ điều hành một doanh nghiệp nha khoa tử tế bằng cảm xúc hay những lời dự đoán mơ hồ của nhân sự. Hãy bắt toàn bộ bộ máy vận hành phải cúi đầu trước sự thật của những con số hiển thị trên Dashboard hằng ngày. Dữ liệu minh bạch chính là chiếc la bàn duy nhất đưa phòng khám của bạn vượt qua vùng tối của cuộc chiến phá giá thị trường."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c010f65c-9f05-491f-b529-d7e53518b9fe','26-marketing-os','f3092b4b-84b9-460e-8ae4-9eccae8bf59f',3,'MODULE 8: OPTIMIZATION SYSTEM - ĐỘNG CƠ CẢI TIẾN LIÊN TỤC VÀ PHÒNG THÍ NGHIỆM TĂNG TRƯỞNG DENTAL OS','module-8-optimization-system-ong-co-cai-tien-lien-tuc-va-phong-thi-nghiem-tang-t',51,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8b59a0ef-f640-4576-9589-47454c737299','26-marketing-os','c010f65c-9f05-491f-b529-d7e53518b9fe',5,'8.1. Định nghĩa và tư duy cốt lõi: triệt tiêu tư duy tĩnh, số hóa phòng thí nghiệm tăng trưởng','81-inh-nghia-va-tu-duy-cot-loi-triet-tieu-tu-duy-tinh-so-hoa-phong-thi-nghiem-ta',52,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d5889379-e97b-44c4-9254-b43aa3e41dc0','8b59a0ef-f640-4576-9589-47454c737299',218,'text','Một sai lầm kinh điển của các chủ phòng khám nha khoa khi làm marketing là **Tư duy đóng băng** - tức là thiết lập xong một chiến dịch quảng cáo, quay xong một bộ video hay viết xong một kịch bản tư vấn rồi kỳ vọng nó sẽ mang lại dòng khách đều đặn mãi mãi. Khi hiệu suất sụt giảm, chi phí sắm khách (CAC) tăng vọt, họ đổ lỗi cho thuật toán của Facebook, TikTok bóp tương tác hoặc đổ lỗi cho thị trường suy thoái. Thực tế tàn nhẫn hơn nhiều: người tiêu dùng trên không gian số rất nhanh chán, và đối thủ cạnh tranh thì liên tục tiến hóa hằng ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c306c20d-80e0-4f4c-b308-9627140f8218','8b59a0ef-f640-4576-9589-47454c737299',219,'text','Trong hệ điều hành **Dental Empire OS**, chúng tôi thiết lập một nguyên lý tối cao: **Marketing không phải là một sự kiện tĩnh, Marketing là một chuỗi các thử nghiệm động diễn ra liên tục. Nếu hệ thống của bạn dừng cải tiến, nó đang chết dần.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a77f5059-f939-4964-a814-4978db915a83','8b59a0ef-f640-4576-9589-47454c737299',220,'text','Phân hệ **Optimization System** đóng vai trò là một "phòng thí nghiệm tăng trưởng kỹ thuật số" (Growth Lab). Phân hệ này chịu trách nhiệm săn tìm các điểm nghẽn (Bottlenecks) làm rò rỉ dòng tiền mặt trên đường ống dữ liệu hằng tuần. Thay vì tối ưu hóa bằng trực giác hay đoán mò, toàn bộ đội ngũ tiếp thị và tư vấn sàn phải tuân thủ kỷ luật khoa học của các bài kiểm tra A/B Testing, liên tục sàng lọc để nhân bản những tài sản chiến thắng (Winners) và khai tử những thử nghiệm thất bại (Losers) dựa trên bằng chứng số liệu thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3e5493b4-0ea1-4995-8ea1-74199eb2a879','26-marketing-os','c010f65c-9f05-491f-b529-d7e53518b9fe',5,'8.2. Vòng lặp tối ưu tuyến tính 7 bước (The Growth Lab Loop)','82-vong-lap-toi-uu-tuyen-tinh-7-buoc-the-growth-lab-loop',53,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('01e634b3-12ce-416d-a198-e86a18194d6a','3e5493b4-0ea1-4995-8ea1-74199eb2a879',221,'text','Mọi hoạt động cải tiến tại phòng khám tuyệt đối không được diễn ra một cách ngẫu hứng mà phải chạy qua đúng vòng lặp khép kín 7 chặng nghiêm ngặt dưới đây:',NULL,NULL,NULL,NULL,NULL);
