INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('38468144-93f8-4538-be6c-3c5190caeff9','319a9d30-9280-4eaa-a3a5-f3ead22a7677',243,'text','Để bánh đà phòng khám tăng tốc mượt mà, *Optimization System* quy hoạch thực địa thành 8 vùng chiến thuật cần liên tục tinh chỉnh:',NULL,NULL,NULL,NULL,NULL);
