INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('89552c42-2620-4389-a840-c10efc48293d','8b19580a-b704-4ce2-8267-8f855fd69314',245,'text','Dưới đây là Khung ma trận phòng thí nghiệm tăng trưởng được số hóa để đội ngũ kỹ thuật bám sát thực thi và cập nhật kết quả hằng tuần:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8055fe1f-a893-43df-abdb-c1bd64cf76cf','8b19580a-b704-4ce2-8267-8f855fd69314',246,'image',NULL,'book/26-marketing-os/558269fa-9ce2-4518-9e69-33c08d3d2f2c-img19.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b0ffc4bb-dd5a-4a40-9db9-3cf7d0cb21b8','8b19580a-b704-4ce2-8267-8f855fd69314',247,'text','Để định lượng chính xác mức độ tăng trưởng của nhóm thử nghiệm so với nhóm đối chứng, hệ điều hành *Data OS* áp dụng phương trình toán học thống kê đo lường **Chỉ số Sức bật Chuyển đổi (Conversion Lift Index)**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15901912-6fb8-4ebc-a18c-be2f9e366e9e','8b19580a-b704-4ce2-8267-8f855fd69314',248,'text','\\text{Conversion Lift (\\%)} = \\frac{CR_{\\text{Test}} - CR_{\\text{Control}}}{CR_{\\text{Control}}} \\times 100\\%',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3899b734-b7dc-4b42-8084-8982d009746b','8b19580a-b704-4ce2-8267-8f855fd69314',249,'text','*Trong đó:*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f5f4d61f-1b41-4d73-8b8e-25109ef774b5','8b19580a-b704-4ce2-8267-8f855fd69314',250,'text','- CR_{\\text{Test}}: Tỷ lệ chuyển đổi của phương án thử nghiệm mới.- CR_{\\text{Control}}: Tỷ lệ chuyển đổi của phương án gốc đang vận hành hiện tại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('55215647-e4c5-4fdb-abcc-11f3e6cbc1bf','8b19580a-b704-4ce2-8267-8f855fd69314',251,'text','Ngưỡng tiêu chuẩn nghiệm thu: Một thử nghiệm chỉ được coi là chiến thắng và cho phép nhân bản diện rộng khi chỉ số \\text{Conversion Lift} \\ge 15\\% và đạt độ tin cậy thống kê tối thiểu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('673c8fe9-3bd7-40ec-b093-02ef6151acaf','26-marketing-os','c010f65c-9f05-491f-b529-d7e53518b9fe',5,'8.5 Bộ đầu ra tài liệu tiêu chuẩn đóng gói (Deliverables Bundle)','85-bo-au-ra-tai-lieu-tieu-chuan-ong-goi-deliverables-bundle',56,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3108d19f-20e9-4c85-843b-7240f869b848','673c8fe9-3bd7-40ec-b093-02ef6151acaf',252,'text','Để phân hệ Optimization System được nghiệm thu hoàn tất và đóng gói thành tài sản mã nguồn vận hành dài hạn cho nha khoa, ban điều hành bắt buộc phải hoàn thiện bộ 6 tài sản quản trị số hóa sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cc20f2eb-217c-4765-b142-1c382fcdabc1','673c8fe9-3bd7-40ec-b093-02ef6151acaf',253,'text','- **Master Optimization Backlog Sheet:** Bảng tổng kho lưu trữ toàn bộ các ý tưởng, giả thuyết và tiến độ các hạng mục thử nghiệm tăng trưởng của phòng khám.- **Weekly Growth Test Plan Blueprint:** Bản kế hoạch hành động phân bổ chi tiết các bài kiểm tra A/B Testing sẽ được kích nổ thực địa trong tuần kế tiếp.- **Standardized A/B Testing Log System:** Biểu mẫu số hóa ghi chép nghiêm ngặt cấu trúc thiết lập bài test, thông số kiểm soát biến số và dữ liệu đối soát tài chính thực thu.- **Central Winning Content Library:** Kho lưu trữ các tài sản nội dung video, bài viết, ad creatives đã được chứng minh chiến thắng để làm mẫu nhân bản cho nhân sự mới.- **Losing Insight & Post-Mortem Library:** Cuốn cẩm nang ghi nhận các bài phân tích chuyên sâu về các chiến dịch thất bại, bóc tách nguyên nhân lỗi sàn để triệt tiêu sự lãng phí ngân sách tương lai.- **Scale / Stop Decision Audit Log:** Biên bản lưu trữ các quyết định dịch chuyển dòng tiền, tăng/giảm ngân sách quảng cáo vĩ mô đã được phê duyệt bởi Bác sĩ Founder Nguyễn Phước Vinh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3471e252-b96d-4a00-af1c-76f908e70f6f','673c8fe9-3bd7-40ec-b093-02ef6151acaf',254,'text','**Mantra tối thượng của Optimization System:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0146d204-7f1d-4a17-b57e-d504b5c9fb30','673c8fe9-3bd7-40ec-b093-02ef6151acaf',255,'text','*"Trong thế giới kinh doanh nha khoa số hóa, người chiến thắng không phải là người có ngân sách quảng cáo lớn nhất, mà là người có tốc độ thử nghiệm, sai và sửa nhanh nhất trên thị trường. Hãy biến phòng khám của bạn thành một phòng thí nghiệm tăng trưởng tử tế, nơi mọi cải tiến nhỏ hằng ngày đều được bảo chứng bằng sự thật minh bạch của dữ liệu."*',NULL,NULL,NULL,NULL,NULL);
